// Language: JavaScript (React)
import React, { useState } from 'react';
import axios from 'axios';

const Register = () => {
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: ''
    });

    const { name, email, password } = formData;

    const onChange = e => setFormData({ ...formData, [e.target.name]: e.target.value });

    const onSubmit = async e => {
        e.preventDefault();
        try {
            // Registering user via backend API
            await axios.post('http://localhost:5000/api/auth/register', formData);
            alert("Registration Successful! Now you can Login.");
        } catch (err) {
            console.error(err.response.data);
            alert("Error in registration.");
        }
    };

    return (
        <div className="container mt-5">
            <div className="row justify-content-center">
                <div className="col-md-5 card p-4 shadow">
                    <h3 className="text-center">Create Ucab Account</h3>
                    <form onSubmit={onSubmit}>
                        <div className="mb-3">
                            <label>Full Name</label>
                            <input type="text" name="name" className="form-control" value={name} onChange={onChange} required />
                        </div>
                        <div className="mb-3">
                            <label>Email Address</label>
                            <input type="email" name="email" className="form-control" value={email} onChange={onChange} required />
                        </div>
                        <div className="mb-3">
                            <label>Password</label>
                            <input type="password" name="password" className="form-control" value={password} onChange={onChange} required />
                        </div>
                        <button type="submit" className="btn btn-success w-100">Register</button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Register;
